import toast from 'react-hot-toast';

const SURPRISE_MOODS = [
  'euphoric', 'nostalgic', 'curious', 'awed', 'playful',
  'reflective', 'energized', 'cathartic', 'cozy', 'bittersweet',
];

export default function MoodResultsPage() {
  const router = useRouter();
  const {
    currentMood, desiredMood, setDesiredMood,
    selectedGenres, results, setResults, setQueryArc, queryArc,
    isLoading, setIsLoading,
  } = useMood();

  const [hoveredCard, setHoveredCard] = useState<string | null>(null);

  // If no results and no mood set, redirect to mood page
  useEffect(() => {
    if (!currentMood && !desiredMood && results.length === 0) {
      router.push('/mood');
    }
  }, [currentMood, desiredMood, results, router]);

  const handleSurprise = useCallback(async () => {
    const randomMood = SURPRISE_MOODS[Math.floor(Math.random() * SURPRISE_MOODS.length)];
    setDesiredMood(randomMood);
    setIsLoading(true);

    try {
      const res = await getArcRecommendations({
        current_mood: currentMood || 'neutral',
        desired_mood: randomMood,
        genres: selectedGenres,
        limit: 12,
      });
      setResults(res.data.results || []);
      setQueryArc(res.data.query_arc || []);
      toast.success(`Surprise! Looking for "${randomMood}" vibes 🎲`);
    } catch {
      toast.error('Failed to get new recommendations');
    } finally {
      setIsLoading(false);
    }
  }, [currentMood, selectedGenres, setDesiredMood, setIsLoading, setResults, setQueryArc]);

  return (
    <div className="page-container" style={{ paddingTop: '1.5rem' }}>
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: '1rem', marginBottom: '1.5rem' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
          <div>
            <h1 style={{ fontSize: 'clamp(1.25rem, 3vw, 1.75rem)', fontWeight: 800, lineHeight: 1.2 }}>
              Your Emotional Matches
            </h1>
            <p style={{ fontSize: '0.78rem', color: 'var(--text-muted)' }}>
              {currentMood && <>Feeling <strong style={{ color: 'var(--danger)' }}>{currentMood}</strong></>}
              {currentMood && desiredMood && ' → '}
              {desiredMood && <>wanting <strong style={{ color: 'var(--accent)' }}>{desiredMood}</strong></>}
              {results.length > 0 && <> · {results.length} movies found</>}
            </p>
          </div>
        </div>

        <button
          onClick={handleSurprise}
          disabled={isLoading}
          className="btn-secondary"
          style={{ display: 'inline-flex', alignItems: 'center', gap: '0.4rem', padding: '0.5rem 1rem', fontSize: '0.8rem' }}
        >
          <Shuffle size={14} /> Surprise Me
        </button>
      </div>

      {/* Loading state */}
      {isLoading && (
        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', padding: '4rem 1rem', gap: '1rem' }}>
          <Loader2 size={32} className="animate-spin" style={{ color: 'var(--accent)' }} />
          <p style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>Matching emotional arcs...</p>
        </div>
      )}

      {/* Empty state */}
      {!isLoading && results.length === 0 && (
        <div style={{ textAlign: 'center', padding: '4rem 1rem' }}>
          <Film size={48} style={{ color: 'var(--text-muted)', marginBottom: '1rem' }} />
          <h2 style={{ fontSize: '1.25rem', fontWeight: 700, marginBottom: '0.5rem' }}>No matches found</h2>
          <p style={{ color: 'var(--text-secondary)', marginBottom: '1.5rem' }}>
            Try different moods or fewer genre filters. Run <code>seed_arc.py</code> to populate the database.
          </p>
          <button onClick={() => router.push('/mood')} className="btn-primary" style={{ padding: '0.6rem 1.5rem' }}>
            Try Again
          </button>
        </div>
      )}

      {/* Results grid */}
      {!isLoading && results.length > 0 && (
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
          gap: '1.25rem',
        }}>
          {results.map((movie: ArcMovieResult) => (
            <div
              key={movie.id}
              className="card card-hover"
              onClick={() => router.push(`/mood/movie/${movie.id}`)}
              onMouseEnter={() => setHoveredCard(movie.id)}
              onMouseLeave={() => setHoveredCard(null)}
              style={{
                cursor: 'pointer',
                overflow: 'hidden',
                transition: 'transform 0.25s ease, border-color 0.2s',
                transform: hoveredCard === movie.id ? 'translateY(-4px)' : 'none',
              }}
            >
              {/* Poster + info row */}
              <div style={{ display: 'flex', gap: '1rem', padding: '1rem' }}>
                {/* Poster */}
                <div style={{
                  width: '90px', height: '135px', borderRadius: 'var(--radius-sm)',
                  overflow: 'hidden', flexShrink: 0, position: 'relative',
                  background: 'var(--bg-elevated)',
                }}>
                  {movie.poster_url ? (
                    <img
                      src={movie.poster_url}
                      alt={movie.title}
                      style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                      loading="lazy"
                    />
                  ) : (
                    <div style={{ width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                      <Film size={24} style={{ color: 'var(--text-muted)' }} />
                    </div>
                  )}

                  {/* Match score badge */}
                  <div style={{
                    position: 'absolute', top: '6px', right: '6px',
                    background: 'rgba(0,0,0,0.75)', backdropFilter: 'blur(8px)',
                    padding: '0.15rem 0.4rem', borderRadius: '6px',
                    fontSize: '0.65rem', fontWeight: 800,
                    color: movie.arc_match_score >= 0.7 ? '#10b981' : movie.arc_match_score >= 0.5 ? '#fbbf24' : '#ef4444',
                  }}>
                    {Math.round(movie.arc_match_score * 100)}%
                  </div>
                </div>

                {/* Info */}
                <div style={{ flex: 1, display: 'flex', flexDirection: 'column', justifyContent: 'space-between' }}>
                  <div>
                    <h3 style={{ fontSize: '0.95rem', fontWeight: 700, lineHeight: 1.25, marginBottom: '0.2rem' }}>
                      {movie.title}
                    </h3>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.4rem' }}>
                      {movie.year && <span style={{ fontSize: '0.72rem', color: 'var(--text-muted)' }}>{movie.year}</span>}
                      {movie.rating > 0 && (
                        <span style={{ display: 'inline-flex', alignItems: 'center', gap: '0.15rem', fontSize: '0.72rem', color: 'var(--star)' }}>
                          <Star size={10} fill="var(--star)" /> {movie.rating.toFixed(1)}
                        </span>
                      )}
                    </div>
                    {/* Genres */}
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.25rem', marginBottom: '0.4rem' }}>
                      {movie.genres.slice(0, 3).map(g => (
                        <span key={g} className="genre-chip" style={{ fontSize: '0.62rem', padding: '0.1rem 0.45rem' }}>{g}</span>
                      ))}
                    </div>
                  </div>

                  {/* Sparkline */}
                  <ArcSparkline labels={movie.arc_labels} width={160} height={40} />
                </div>
              </div>

              {/* Arc explanation */}
              <div style={{
                padding: '0.6rem 1rem', borderTop: '1px solid var(--border)',
                background: hoveredCard === movie.id ? 'var(--bg-elevated)' : 'transparent',
                transition: 'background 0.2s',
              }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.35rem', marginBottom: '0.2rem' }}>
                  <Sparkles size={11} style={{ color: 'var(--purple)' }} />
                  <span style={{ fontSize: '0.68rem', fontWeight: 600, color: 'var(--purple)' }}>Emotional Arc</span>
                </div>
                <p style={{ fontSize: '0.72rem', color: 'var(--text-muted)', lineHeight: 1.4 }}>
                  {movie.arc_explanation || movie.arc_labels.join(' → ')}
                </p>
              </div>

              {/* Hover tooltip: "Why this movie" */}
              {hoveredCard === movie.id && movie.overview && (
                <div style={{
                  padding: '0.75rem 1rem', borderTop: '1px solid var(--border)',
                  background: 'var(--bg-elevated)',
                  animation: 'fadeIn 0.2s ease',
                }}>
                  <span style={{ fontSize: '0.68rem', fontWeight: 700, color: 'var(--accent)', marginBottom: '0.25rem', display: 'block' }}>
                    Why this movie?
                  </span>
                  <p style={{ fontSize: '0.72rem', color: 'var(--text-secondary)', lineHeight: 1.4 }}>
                    {movie.overview.length > 150 ? movie.overview.substring(0, 150) + '...' : movie.overview}
                  </p>
                </div>
              )}
            </div>
          ))}
        </div>
      )}

      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(-4px); }
          to { opacity: 1; transform: translateY(0); }
        }
      `}</style>
    </div>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { useAuth } from '@/context/AuthContext';
import { getMovieDetails, getRecommendations, trackActivity } from '@/lib/api';
import api from '@/lib/api';
import PosterImage from '@/components/PosterImage';
import MovieCard from '@/components/MovieCard';
import SaveButton from '@/components/SaveButton';
import { motion } from 'framer-motion';
import {
  Star, ArrowLeft, Send, Loader2, AlertCircle, Clock, Globe,
  DollarSign, BarChart2, Users, MapPin, Briefcase, Tag,
} from 'lucide-react';
import toast from 'react-hot-toast';
import Link from 'next/link';
import type { Movie } from '@/components/MovieCard';
import { useIsMobile } from '@/hooks/useIsMobile';

interface CastMember {
  name: string;
  character?: string;
  order?: number;
}

interface Review {
  id: number;
  username: string;
  review_text: string;
  sentiment_label: 'positive' | 'negative' | 'neutral';
  sentiment_confidence: number;
  created_at: string;
}

interface MovieDetail {
  title: string;
  overview?: string;
  poster?: string;        // API returns 'poster'
  poster_url?: string;    // some responses return 'poster_url'
  vote_average?: number;
  rating?: number;
  vote_count?: number;
  year?: number;
  genres?: string[];
  cast?: CastMember[];
  director?: string;
  runtime?: number;
  tagline?: string;
  budget?: number;
  revenue?: number;
  popularity?: number;
  status?: string;
  original_language?: string;
  release_date?: string;
  production_countries?: string[];
  spoken_languages?: string[];
  production_companies?: string[];
  keywords?: string[];
}

const sentimentStyle = (label: string) => {
  if (label === 'positive') return 'badge-positive';
  if (label === 'negative') return 'badge-negative';
  return 'badge-neutral';
};
const sentimentIcon = (label: string) => label === 'positive' ? '✅' : label === 'negative' ? '❌' : '➖';

function formatCurrency(n: number | undefined | null): string | null {
  if (!n || n <= 0) return null;
  if (n >= 1_000_000_000) return `$${(n / 1_000_000_000).toFixed(1)}B`;
  if (n >= 1_000_000) return `$${(n / 1_000_000).toFixed(1)}M`;
  if (n >= 1_000) return `$${(n / 1_000).toFixed(0)}K`;
  return `$${n}`;
}

function MetaChip({ label }: { label: string }) {
  return (
    <span style={{
      padding: '0.2rem 0.55rem', borderRadius: '6px', fontSize: '0.72rem', fontWeight: 600,
      background: 'var(--bg-elevated)', border: '1px solid var(--border)', color: 'var(--text-secondary)',
    }}>{label}</span>
  );
}

export default function MovieDetailPage() {
  const { title } = useParams<{ title: string }>();
  const { user } = useAuth();
  const router = useRouter();
  const [movie, setMovie] = useState<MovieDetail | null>(null);
  const [recs, setRecs] = useState<Movie[]>([]);
  const [reviews, setReviews] = useState<Review[]>([]);
  const [reviewText, setReviewText] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [loading, setLoading] = useState(true);
  const isMobile = useIsMobile();

  const decodedTitle = decodeURIComponent(title);

  const fetchReviews = useCallback(async () => {
    try {
      const res = await api.get(`/movies/${encodeURIComponent(decodedTitle)}/reviews`);
      setReviews(res.data.reviews || res.data || []);
    } catch { /* no reviews yet */ }
  }, [decodedTitle]);

  useEffect(() => {
    // Track movie click for future personalized recommendations
    trackActivity({ activity_type: 'movie_click', movie_title: decodedTitle, page_url: `/movie/${title}` });

    // Load all 3 data sources in parallel for maximum speed
    (async () => {
      setLoading(true);
      const [detRes, recRes, revRes] = await Promise.allSettled([
        getMovieDetails(decodedTitle),
        getRecommendations(decodedTitle),
        api.get(`/movies/${encodeURIComponent(decodedTitle)}/reviews`),
      ]);

      if (detRes.status === 'fulfilled') {
        const d = detRes.value.data;
        setMovie(d.movie || d);
      } else {
        toast.error('Movie not found');
      }

      if (recRes.status === 'fulfilled') {
        const r = recRes.value.data;
        setRecs(r.recommendations || r.movies || r || []);
      }

      if (revRes.status === 'fulfilled') {
        setReviews(revRes.value.data?.reviews || revRes.value.data || []);
      }

      setLoading(false);
    })();
  }, [decodedTitle, title]);  

  const submitReview = async () => {
    if (!reviewText.trim()) { toast.error('Write something first'); return; }
    if (!user) { toast.error('Please log in to review'); return; }
    setSubmitting(true);
    try {
      await api.post(`/movies/${encodeURIComponent(decodedTitle)}/reviews`, { review_text: reviewText });
      toast.success('Review posted!');
      setReviewText('');
      fetchReviews();
    } catch { toast.error('Failed to post review'); }
    finally { setSubmitting(false); }
  };

  const sentSummary = reviews.length > 0 ? {
    pos: reviews.filter(r => r.sentiment_label === 'positive').length,
    neg: reviews.filter(r => r.sentiment_label === 'negative').length,
    neu: reviews.filter(r => r.sentiment_label === 'neutral').length,
  } : null;

  if (loading) return (
    <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '1rem' }}>
        <Loader2 size={36} color="var(--accent)" className="animate-spin" />
        <p style={{ color: 'var(--text-muted)', fontSize: '0.875rem' }}>Loading movie details…</p>
      </div>
    </div>
  );

  if (!movie) return (
    <div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: '1rem' }}>
      <AlertCircle size={40} color="var(--danger)" />
      <p style={{ color: 'var(--text-secondary)' }}>Movie not found</p>
      <Link href="/explore" className="btn-primary" style={{ textDecoration: 'none' }}>Back to Explore</Link>
    </div>
  );

  // Resolve poster: API can return 'poster' or 'poster_url'
  const posterSrc = movie.poster || movie.poster_url || null;
  const rating = movie.vote_average ?? movie.rating;
  const castNames = (movie.cast || []).map(c => typeof c === 'string' ? c : c.name).filter(Boolean);
  const budgetStr = formatCurrency(movie.budget);
  const revenueStr = formatCurrency(movie.revenue);

  return (
    <div className="page-container" style={isMobile ? { padding: '1rem' } : undefined}>


      {/* Hero section */}
      <motion.div initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.4 }}
        style={isMobile ? { display: 'grid', gridTemplateRows: 'auto 1fr', gap: '2.5rem', marginBottom: '3rem', alignItems: 'start',marginTop: '10px' } : { display: 'grid', gridTemplateColumns: 'auto 1fr', gap: '2.5rem', marginBottom: '3rem', alignItems: 'start',marginTop: '20px' }}>
        {/* Poster */}
        {isMobile ? (  <div style={{ display: 'flex', alignItems: 'center',justifyContent: 'center',flex:"inline-flex"}}><div style={{ width:'200px', flexShrink: 0}}>
          <div className="card" style={{ overflow: 'hidden', borderRadius: '1rem', aspectRatio: '2/3', minHeight: '280px'}}>
            <PosterImage src={posterSrc} alt={movie.title} style={{ width: '100%', height: '100%', objectFit: 'cover', display: 'block' }} />
          </div>
          {user && (
            <div style={{ marginTop: '1rem' }}>
              <SaveButton movieTitle={movie.title} />
            </div>

          )}
        </div>
      </div>) : (  <div style={{ width: '346px', flexShrink: 0 }}>
          <div className="card" style={{ overflow: 'hidden', borderRadius: '1rem', aspectRatio: '2/3', minHeight: '280px' }}>
            <PosterImage src={posterSrc} alt={movie.title} style={{ width: '100%', height: '100%', objectFit: 'cover', display: 'block' }} />
          </div>
          {user && (
            <div style={{ marginTop: '1rem' }}>
              <SaveButton movieTitle={movie.title} />
            </div>
          )}
        </div>)}


        {/* Info */}
        <div>
          {movie.tagline && (
            <p style={{ color: 'var(--accent)', fontSize: '0.8rem', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '0.5rem' }}>
