           <button onClick={handleVerifyOtp} disabled={loading || otpCode.length !== 6} className="btn-primary" style={{ width: '100%', padding: '1rem', fontSize: '1.1rem' }}>
              {loading ? <Loader2 size={20} className="animate-spin mx-auto" /> : 'Verify Email'}
