                        {/* Rating badge */}
                        {rating != null && rating > 0 && (
                          <div style={{
                            position: 'absolute', bottom: '0.4rem', left: '0.4rem',
                            display: 'flex', alignItems: 'center', gap: '0.2rem',
                            background: 'rgba(0,0,0,0.55)', borderRadius: '0.375rem',
                            padding: '0.15rem 0.4rem', backdropFilter: 'blur(4px)',
