function SeriesStackCard({
  stack,
  onClick,
  onRemoveSingle,
}: {
  stack: MovieStack;
  onClick: () => void;
  onRemoveSingle: (movie: Movie) => void;
}) {
  const count   = stack.movies.length;
  const isSeries = count > 1;
